<template>
  <div>
    <el-breadcrumb separator="/">
      <el-breadcrumb-item :to="{ path: '/' }">йҰ–йЎө</el-breadcrumb-item>
      <el-breadcrumb-item to="">SIGжҢҒд»“з®ЎзҗҶ</el-breadcrumb-item>
      <el-breadcrumb-item>дҝЎеҸ·еҲ—иЎЁ</el-breadcrumb-item>
    </el-breadcrumb>
    <div class="project-top">
      <el-select v-model="strategy_name" clearable placeholder="йҖүжӢ©зӯ–з•Ҙ" @change="getSignalList" @clear="getSignalList">
        <el-option v-for="item in strategyOptions" :key="item.name" :label="item.name" :value="item.name">
          <span style="float: left">{{ item.name }}</span>
          <span style="float: right; color: #8492a6; font-size: 13px">{{ item.label }}</span>
        </el-option>
      </el-select>
      <el-button type="primary" @click="refreshSignalList()">еҲ·ж–°еҲ—иЎЁ</el-button>
    </div>
    <el-table :span-method="objectSpanMethod" :data="signalList" border style="width: 100%; margin-top: 20px;"
      v-loading="loading">
      <el-table-column prop="pair_id" label="й…ҚеҜ№ID">
      </el-table-column>
      <!-- <el-table-column prop="id" label="ID"></el-table-column> -->
      <el-table-column prop="name" label="зӯ–з•ҘеҗҚз§°">
      </el-table-column>
      <el-table-column label="зұ»еһӢ" align="center">
        <template slot-scope="scope">
          <span>{{ positionTypeLabel(scope.row) }}</span>
        </template>
      </el-table-column>
      <!-- <el-table-column prop="symbol" label="дәӨжҳ“еҜ№" align="center"></el-table-column> -->
      <el-table-column prop="direction" label="ж–№еҗ‘" align="center">
        <template slot-scope="scope">
          <el-tag :type="orderSideLabel(scope.row) === 'buy' ? 'success' : 'danger'">
            {{ orderSideLabel(scope.row) }}
          </el-tag>
        </template>
      </el-table-column>
      <el-table-column prop="size" label="дҝЎеҸ·зұ»еһӢ" align="center">
        <template slot-scope="scope">
          {{ scope.row.size == '1' || scope.row.size == '-1' || scope.row.size == 1 || scope.row.size == -1 ? 'ејҖд»“' : 'е№ід»“' }}
        </template>
      </el-table-column>
      <el-table-column prop="price" label="д»·ж ј" align="center">
        <template slot-scope="scope">
          {{ formatNumber(scope.row.price) }}
        </template>
      </el-table-column>
      <el-table-column prop="timestamp" label="ж—Ҙжңҹ/ж—¶й—ҙ" align="center" width="180">
        <template slot-scope="scope">
          {{ scope.row.position_at }}
        </template>
      </el-table-column>
      <el-table-column prop="loss_profit" label="дәӨжҳ“зӣҲдәҸ" align="center">
        <template slot-scope="scope">
          {{ formatNumber(scope.row.loss_profit) || 0 }}
        </template>
      </el-table-column>
      <el-table-column prop="stage_profit_loss" label="йҳ¶ж®өзӣҲдәҸ" align="center">
        <template slot-scope="scope">
          {{ formatNumber(scope.row.stage_profit_loss) || 0 }}
        </template>
      </el-table-column>
      <el-table-column prop="count_profit_loss" label="жҖ»зӣҲдәҸ" align="center">
        <template slot-scope="scope">
          {{ formatNumber(scope.row.count_profit_loss) || 0 }}
        </template>
      </el-table-column>
      <el-table-column prop="status" label="зҠ¶жҖҒ" align="center">
        <template slot-scope="scope">
          <el-tag
            :type="scope.row.status === 'pending' ? 'warning' : (scope.row.status === 'processed' ? 'success' : 'info')">
            {{ scope.row.status === 'pending' ? 'иҝӣиЎҢдёӯ' : (scope.row.status === 'processed' ? 'е·Іе®ҢжҲҗ' : scope.row.status) }}
          </el-tag>
        </template>
      </el-table-column>
    </el-table>

    <el-row class="pages">
      <el-col :span="24">
        <div style="float:right;">
          <wbc-page :total="total" :pageSize="pageSize" :currPage="currentPage" @changeLimit="limitPaging"
            @changeSkip="skipPaging"></wbc-page>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import Page from "@/components/Page.vue";
import { get } from "@/common/axios.js";

export default {
  data() {
    return {
      currentPage: 1,
      pageSize: 10,
      total: 0,
      PageSearchWhere: {
        page: 1,
        limit: 10,
      },
      signalList: [],
      loading: false,
      strategyOptions: [],
      strategy_name: 'Y1.1',
    };
  },
  created() {
    this.getSignalList();
    this.getAllStrategyList();
  },
  components: {
    "wbc-page": Page, //еҠ иҪҪеҲҶйЎөз»„д»¶
  },
  methods: {
    objectSpanMethod({ row, column, rowIndex, columnIndex }) {
      if (columnIndex === 0) {
        const pairId = row.pair_id;

        // зЎ®дҝқ signalList жҳҜжҢү pair_id жҺ’еҘҪеәҸзҡ„
        const firstIndex = this.signalList.findIndex(item => item.pair_id === pairId);
        const count = this.signalList.filter(item => item.pair_id === pairId).length;

        if (rowIndex === firstIndex) {
          return {
            rowspan: count,
            colspan: 1
          };
        } else {
          return {
            rowspan: 0,
            colspan: 0
          };
        }
      }
    },
    getAllStrategyList() {
      get("/Grid/grid/getAllStrategyList", {}, json => {
        if (json.data.code == 10000) {
          this.strategyOptions = json.data.data;
        } else {
          this.$message.error("еҠ иҪҪзӯ–з•Ҙж•°жҚ®еӨұиҙҘ");
        }
      });
    },
    getSignalList() {
      this.loading = true;
      const params = {
        page: this.currentPage,
        limit: this.pageSize,
        strategy_name: this.strategy_name,
      };

      get("/Grid/grid/getSignalsList", params, response => {
        this.loading = false;
        if (response.data.code == 10000) {
          this.signalList = response.data.data.lists || [];
          this.total = response.data.data.count || 0;
        } else {
          this.$message.error(response.data.msg || 'иҺ·еҸ–дҝЎеҸ·еҲ—иЎЁеӨұиҙҘ');
        }
      });
    },

    async refreshSignalList() {
      // е»¶иҝҹ1-2з§’еҶҚз»§з»ӯжү§иЎҢ
      this.loading = true;
      const delay = Math.random() * 1000; // 1000~2000ms
      await new Promise(resolve => setTimeout(resolve, delay));
      this.getSignalList();
    },

    formatNumber(num) {
      if (isNaN(num)) return '--';
      // Format number with 4 decimal places
      return parseFloat(num).toFixed(1);
    },

    /**
     * дёҺ api_service / ж–° leader дёҖиҮҙпјҡdirection дёәе§”жүҳдҫ§пјҲbuyвҶ’long, sellвҶ’shortпјүгҖӮ
     * е№ід»“ long+0=е№із©әвҶ’з©әеӨҙеҮәеңәпјӣshort+0=е№іеӨҡвҶ’еӨҡеӨҙеҮәеңәгҖӮ
     */
    positionTypeLabel(row) {
      const sz = parseInt(row.size, 10);
      const dir = (row.direction || '').toLowerCase();
      if (sz === 1) return 'еӨҡеӨҙиҝӣеңә';
      if (sz === -1) return 'з©әеӨҙиҝӣеңә';
      if (sz === 0) {
        if (dir === 'long') return 'з©әеӨҙеҮәеңә';
        if (dir === 'short') return 'еӨҡеӨҙеҮәеңә';
        return 'е№ід»“';
      }
      return '--';
    },

    /** е§”жүҳж–№еҗ‘ buy/sellпјҲдёҺ direction дёҖиҮҙпјү */
    orderSideLabel(row) {
      return (row.direction || '').toLowerCase() === 'long' ? 'buy' : 'sell';
    },

    getStatusTagType(status) {
      const statusMap = {
        'pending': 'warning',
        'executed': 'success',
        'canceled': 'info',
        'failed': 'danger'
      };
      return statusMap[status] || 'info';
    },

    getStatusText(status) {
      const statusTextMap = {
        'pending': 'еҫ…жү§иЎҢ',
        'executed': 'е·Іжү§иЎҢ',
        'canceled': 'е·ІеҸ–ж¶Ҳ',
        'failed': 'еӨұиҙҘ'
      };
      return statusTextMap[status] || status;
    },
    limitPaging(limit) {
      //иөӢеҖјеҪ“еүҚжқЎж•°
      this.pageSize = limit;
      this.getSignalList(); //еҲ·ж–°еҲ—иЎЁ
    },
    skipPaging(page) {
      //иөӢеҖјеҪ“еүҚйЎөж•°
      this.currentPage = page;
      this.getSignalList(); //еҲ·ж–°еҲ—иЎЁ
    },
  }
};
</script>

<style scoped>
.project-top {
  display: flex;
  align-items: center;
  margin-bottom: 20px;
  margin-top: 20px;
  justify-content: space-between;
}
.el-breadcrumb {
  margin-bottom: 20px;
}

.pagination {
  margin-top: 20px;
  text-align: right;
}

.el-tag {
  margin: 2px;
}

.pages {
  margin-top: 0 !important;
  margin-bottom: 80px !important;
}
</style>


