<template>
    <nav>
        <div class="grid-content">
            <div class="pagination">
                <el-pagination
                @size-change="handleSizeChange"
                @current-change="handleCurrentChange"
                :current-page="currPage"
                :page-sizes="[10, 20, 30, 50, 100]"
                :page-size="pageSize"
                layout="total, sizes, prev, pager, next, jumper"
                :total="total">
                </el-pagination>
            </div>
          </div>
    </nav>
</template>
<script>
  export default {
    props: ['total', 'pageSize', 'currPage'],//жҺҘеҸ—еҲҶйЎөй…ҚзҪ®ж•°жҚ®    totalпјҡжҖ»жқЎж•°  currPageпјҡеҪ“еүҚйЎө  pageSizeпјҡжҜҸйЎөжҳҫзӨәжқЎж•°
    data() {
        return {
        }
    },
    methods: {
      handleSizeChange(limit) { //жҜҸйЎөжҳҫзӨәжқЎж•°дәӢд»¶
        this.$emit('changeLimit', limit)  //е°ҶеҪ“еүҚйЎөдј з»ҷдё»з»„д»¶
      },
      handleCurrentChange(page) { //еҪ“еүҚйЎөдәӢд»¶
        this.$emit('changeSkip', page)  //е°ҶеҪ“еүҚйЎөдј з»ҷдё»з»„д»¶
      },
    }
  }
</script>
<style scoped>
  .pagination{
    float: right;
  }
</style>


